select count(*) from postgres.comments as c, postgres.posts as p, postgres.postlinks as pl, postgres.votes as v, postgres.badges as b, postgres.users as u where p.id = c.postid and p.id = pl.relatedpostid and p.id = v.postid and u.id = p.owneruserid and u.id = b.userid and c.creationdate>=timestamp '2010-08-06 12:21:39' and c.creationdate<=timestamp '2014-09-11 20:55:34' and p.score>=0 and p.score<=13 and p.favoritecount>=0 and pl.linktypeid=1 and pl.creationdate>=timestamp '2011-03-11 18:50:29' and v.votetypeid=2 and v.creationdate<=timestamp '2014-09-11 00:00:00' and u.reputation>=1 and u.creationdate>=timestamp '2011-02-17 03:42:02' and u.creationdate<=timestamp '2014-09-01 10:54:39';
